openscad:
$fn=60;
case_dia=40; // [20:1:80]
case_height=8; // [4:1:15]
dial_dia=34; // [15:1:70]
bezel_height=2; // [0.5:0.5:5]
hand_thick=1.2; // [0.5:0.2:3]
hour_len=9; // [4:1:20]
minute_len=13; // [6:1:25]
second_len=15; // [8:1:25]
date_size=5; // [3:1:10]
union(){
color("silver") difference(){
cylinder(d=case_dia,h=case_height);
translate([0,0,case_height-bezel_height]) cylinder(d=case_dia-3,h=bezel_height+0.1);
translate([0,0,case_height-1]) cylinder(d=dial_dia+1,h=2);
}
color("white") translate([0,0,case_height-bezel_height]) cylinder(d=dial_dia,h=1.5);
for(i=[0:11]){
rotate([0,0,i*30]) translate([dial_dia/2-3,0,case_height-bezel_height+1.6]) color("black") cube([3,1.2,1.2],center=true);
}
color("black") translate([date_size/2+3,0,case_height-bezel_height+1.6]) cube([date_size,date_size,1.2],center=true);
color("black") translate([date_size/2+3,0,case_height-bezel_height+2.8]) linear_extrude(0.6) text("15",size=2.5,halign="center",valign="center");
color("black") rotate([0,0,300]) translate([0,0,case_height-bezel_height+2.5]) cube([hand_thick,hour_len,1.5],center=true);
color("black") rotate([0,0,40]) translate([0,0,case_height-bezel_height+2.7]) cube([hand_thick*0.8,minute_len,1.3],center=true);
color("red") rotate([0,0,180]) translate([0,0,case_height-bezel_height+2.9]) cube([hand_thick*0.5,second_len,1.1],center=true);
}
